1	package bind
2	
3	import (
4		"fmt"
5		"net/netip"
6		"testing"
7	)
8	
9	// TestPerPeerResequencerLifecycle is the T87 acceptance: with TWO peerStates bound over the
10	// same shared sockets, each peer's receive resequencer is an INDEPENDENT release plane. Two
11	// interleaved outer-seq streams stay separated (each peer's Pop yields only its own stream),
12	// a Close→Open cycle re-builds EVERY bound peer's resequencer + send Codec fresh (not just
13	// the primary's via promotion — the symmetry with closeSocketsLocked that a concentrator peer
14	// relies on across a reconnect), and a Rebaseline triggered on peer A (via the edge hub-
15	// failover SetPeerRemote) leaves peer B's release point untouched — the D32-class regression,
16	// now proven per-peer.
17	func TestPerPeerResequencerLifecycle(t *testing.T) {
18		psk := testKey(t, 0x71)
19		clk := newFakeClock()
20		m, _, _ := newProbingMultipath(t, loopbackPaths(1), psk, clk)
21		if _, _, err := m.Open(0); err != nil {
22			t.Fatalf("Open: %v", err)
23		}
24		t.Cleanup(func() { _ = m.Close() })
25	
26		primary := m.peerState
27		second := bindSecondPeer(t, m, "peer-2", psk, clk)
28	
29		srcA := netip.MustParseAddrPort("203.0.113.1:51820")
30		srcB := netip.MustParseAddrPort("198.51.100.7:51820")
31	
32		// --- Two interleaved streams stay separated. ---
33		// Feed peer A and peer B the SAME outer-seq positions with DISTINCT payloads, interleaved.
34		// Each peer's resequencer must release ONLY its own payloads, in order — a shared/global
35		// buffer would cross the streams.
36		stream := []uint64{100, 101, 102}
37		for _, seq := range stream {
38			primary.resequencer.Load().Observe(seq, []byte(fmt.Sprintf("A-%d", seq)), srcA)
39			second.resequencer.Load().Observe(seq, []byte(fmt.Sprintf("B-%d", seq)), srcB)
40		}
41		for _, seq := range stream {
42			gotA, okA := primary.resequencer.Load().Pop()
43			if wantA := fmt.Sprintf("A-%d", seq); !okA || string(gotA.Payload) != wantA {
44				t.Fatalf("peer A Pop = %q (ok=%v), want %q (streams crossed)", gotA.Payload, okA, wantA)
45			}
46			if gotA.Src != srcA {
47				t.Fatalf("peer A item src = %v, want %v", gotA.Src, srcA)
48			}
49			gotB, okB := second.resequencer.Load().Pop()
50			if wantB := fmt.Sprintf("B-%d", seq); !okB || string(gotB.Payload) != wantB {
51				t.Fatalf("peer B Pop = %q (ok=%v), want %q (streams crossed)", gotB.Payload, okB, wantB)
52			}
53			if gotB.Src != srcB {
54				t.Fatalf("peer B item src = %v, want %v", gotB.Src, srcB)
55			}
56		}
57	
58		// --- The separation survives a Close→Open cycle: EVERY bound peer's datapath is re-built. ---
59		primaryRQ1 := primary.resequencer.Load()
60		secondRQ1 := second.resequencer.Load()
61		if err := m.Close(); err != nil {
62			t.Fatalf("Close: %v", err)
63		}
64		// Close clears every peer's per-Open state; the second peer's send Codec must be nil now.
65		if second.sendCodec != nil {
66			t.Fatalf("second peer sendCodec not cleared by Close")
67		}
68		if _, _, err := m.Open(0); err != nil {
69			t.Fatalf("re-Open: %v", err)
70		}
71	
72		primaryRQ2 := primary.resequencer.Load()
73		secondRQ2 := second.resequencer.Load()
74		// Both peers got a FRESH resequencer (a distinct instance) on re-Open — without the per-peer
75		// rebuild the second peer would keep its stale instance (or a nil send Codec).
76		if primaryRQ2 == nil || primaryRQ2 == primaryRQ1 {
77			t.Fatalf("primary resequencer not re-built on re-Open (fresh=%v)", primaryRQ2 != primaryRQ1)
78		}
79		if secondRQ2 == nil || secondRQ2 == secondRQ1 {
80			t.Fatalf("second peer resequencer not re-built on re-Open (Open only rebuilt the primary): fresh=%v", secondRQ2 != secondRQ1)
81		}
82		if second.sendCodec == nil {
83			t.Fatalf("second peer sendCodec not re-built on re-Open (Open only rebuilt the primary)")
84		}
85	
86		// --- Rebaseline on peer A leaves peer B's release point untouched (D32, per-peer). ---
87		// Advance BOTH peers' release point to a high outer-seq (the prior hub's high-rate stream).
88		const high = uint64(10000)
89		for _, ps := range []*peerState{primary, second} {
90			ps.resequencer.Load().Observe(high, []byte("high"), srcA)
91			if _, ok := ps.resequencer.Load().Pop(); !ok {
92				t.Fatalf("expected the high seq to release and advance next")
93			}
94		}
95	
96		// The edge hub-failover switch: SetPeerRemote re-baselines ONLY the primary (peer A).
97		m.SetPeerRemote(netip.MustParseAddrPort("192.0.2.9:51820"))
98	
99		if got := primary.resequencer.Load().Stats().Rebaselines; got != 1 {
100			t.Fatalf("primary Rebaselines = %d, want 1 (SetPeerRemote must re-baseline the switched peer)", got)
101		}
102		if got := second.resequencer.Load().Stats().Rebaselines; got != 0 {
103			t.Fatalf("second peer Rebaselines = %d, want 0 (a hub switch on peer A must not touch peer B)", got)
104		}
105	
106		// A LOW seq now: peer A (re-baselined) re-anchors on it and DELIVERS; peer B (release point
107		// still at high+1) rejects it as a suspect out-of-band frame and delivers NOTHING — proof its
108		// `next` was untouched by peer A's re-baseline.
109		const low = uint64(1)
110		primary.resequencer.Load().Observe(low, []byte("A-reanchor"), srcA)
111		gotLow, okLow := primary.resequencer.Load().Pop()
112		if !okLow || string(gotLow.Payload) != "A-reanchor" {
113			t.Fatalf("peer A did not re-anchor on the low seq after re-baseline: got %q (ok=%v)", gotLow.Payload, okLow)
114		}
115	
116		second.resequencer.Load().Observe(low, []byte("B-should-drop"), srcB)
117		if it, ok := second.resequencer.Load().Pop(); ok {
118			t.Fatalf("peer B delivered the low seq %q — its release point was disturbed by peer A's re-baseline", it.Payload)
119		}
120		if got := second.resequencer.Load().Stats().DroppedSuspect; got == 0 {
121			t.Fatalf("peer B did not reject the low seq as suspect (its next was moved): DroppedSuspect=%d", got)
122		}
123	}
