1	package bind
2	
3	import (
4		"io"
5		"net/netip"
6		"testing"
7		"time"
8	
9		"github.com/7mind/wanbond/internal/config"
10		"github.com/7mind/wanbond/internal/log"
11		"github.com/7mind/wanbond/internal/reseq"
12		"github.com/7mind/wanbond/internal/sched"
13		"github.com/7mind/wanbond/internal/telemetry"
14	)
15	
16	// bindSecondPeer constructs a SECOND peerState over the SAME shared sockets an already-Open
17	// Multipath holds, and binds it into m.peers/m.peersByName. It stands in for the concentrator's
18	// per-peer wiring (a later G4 task) so this test can exercise the runtime shared-path fan-out
19	// while >=2 peerStates are bound: it gives the peer its own DynamicScheduler, its own probe
20	// initiator factory + boot probers (aligned with the durable membership m.defs), and a
21	// peerPathState VIEW over each currently-bound shared socket. It must run after m.Open.
22	func bindSecondPeer(t testing.TB, m *Multipath, name string, psk config.Key, clk telemetry.Clock) *peerState {
23		t.Helper()
24		lg, err := log.New("error", io.Discard)
25		if err != nil {
26			t.Fatalf("build logger: %v", err)
27		}
28		cfg := telemetry.ProberConfig{
29			LossWindow: 0,
30			Liveness:   telemetry.LivenessConfig{DownAfter: testProbeDownAfter, UpAfterSuccesses: testProbeUpSucc},
31		}
32		// A DISTINCT probe session id from the primary's: a concentrator peer runs its own probe
33		// session, and it proves the fan-out mints genuinely per-peer probers (not shared handles).
34		const secondPeerSessionID uint64 = 0x0123456789ABCDEF
35		newProber := func(pname string, id uint8) *telemetry.Prober {
36			return telemetry.NewProber(pname, id, secondPeerSessionID, psk, cfg, clk, lg)
37		}
38	
39		m.mu.Lock()
40		defer m.mu.Unlock()
41	
42		// Boot probers aligned with the durable membership (m.defs), stamped with each shared
43		// socket's path-id so DATA and PROBE agree on the wire, exactly as Open does for the primary.
44		probers := make([]*telemetry.Prober, len(m.defs))
45		health := make([]sched.PathHealth, len(m.defs))
46		byName := make(map[string]*telemetry.Prober, len(m.defs))
47		for i := range m.defs {
48			var id uint8
49			for _, sp := range m.shared {
50				if sp.name == m.defs[i].Name {
51					id = sp.id
52				}
53			}
54			probers[i] = newProber(m.defs[i].Name, id)
55			health[i] = probers[i]
56			byName[m.defs[i].Name] = probers[i]
57		}
58		scheduler, err := sched.NewActiveBackup(health, sched.Config{FailbackAfter: time.Hour}, clk, lg)
59		if err != nil {
60			t.Fatalf("build second-peer scheduler: %v", err)
61		}
62		// Build the peer through the SAME seam production uses (newPeerState), so its Reflector
63		// and every codec derive from THIS peer's psk (T84) rather than being hand-wired.
64		p := newPeerState(name, psk, scheduler, newProber, probers)
65		sendCodec, err := p.newCodec()
66		if err != nil {
67			t.Fatalf("build second-peer send codec: %v", err)
68		}
69		p.sendCodec = sendCodec
70		// A per-peer receive resequencer, exactly as Open Stores for the primary — the
71		// concentrator's per-peer wiring (a later G4 task) builds this; the helper stands in
72		// so handleInbound can route this peer's DATA stream into its OWN buffer and the
73		// engine-facing drainer can release it under this peer's virtual endpoint.
74		p.resequencer.Store(reseq.New(resequencerWindow, resequencerTimeout, reseq.SystemClock{}))
75		// A peerPathState VIEW over each bound shared socket, index-aligned with m.shared (which,
76		// with no deferred paths, is also aligned with m.defs) so the peer's scheduler and paths
77		// stay index-aligned exactly as the primary's do.
78		for _, sp := range m.shared {
79			codec, cerr := p.newCodec()
80			if cerr != nil {
81				t.Fatalf("build second-peer path codec: %v", cerr)
82			}
83			pp := &peerPathState{sharedPathState: sp, peer: p, codec: codec, prober: byName[sp.name]}
84			p.paths = append(p.paths, pp)
85			// Publish this peer's view for the receive demux, exactly as the concentrator's per-peer
86			// wiring does, so handleInbound source-demuxes the shared socket to the owning peer (T88).
87			sp.addViewLocked(pp)
88		}
89		m.peers = append(m.peers, p)
90		m.peersByName[name] = p
91		// Register the peer's virt so an outbound Send to it routes to THIS peerState (the
92		// concentrator's per-peer wiring does the same when it binds a peer).
93		m.peerByVirt[p.virt] = p
94		// Republish the lock-free peer view the receive drainer iterates, so this newly-bound
95		// peer's resequencer is drained (mirrors the concentrator wiring's obligation).
96		m.republishPeersLocked()
97		return p
98	}
99	
100	// pathNamesOfPeer snapshots a peer's per-(peer,path) view names, for assertions.
101	func pathNamesOfPeer(p *peerState) []string {
102		out := make([]string, len(p.paths))
103		for i, pp := range p.paths {
104			out[i] = pp.name
105		}
106		return out
107	}
108	
109	// peerPathByName returns the peer's per-(peer,path) view of the named shared path, or nil.
110	func peerPathByName(p *peerState, name string) *peerPathState {
111		for _, pp := range p.paths {
112			if pp.name == name {
113				return pp
114			}
115		}
116		return nil
117	}
118	
119	// TestMultipathSharedPathFanOutAcrossPeers is the G4 fan-out acceptance for the peerState /
120	// pathState split: with TWO peerStates bound over the same shared sockets, a runtime AddPath of
121	// a SHARED path must instantiate per-(peer,path) state (codec, remote, prober, tx/rx) for BOTH
122	// peers, and a runtime RemovePath must tear that per-(peer,path) state down for BOTH peers,
123	// leaving each peer's remaining paths untouched. It proves the fan-out has a single owner
124	// (attachSharedPathLocked / RemovePath) exercised while >=2 peerStates exist.
125	func TestMultipathSharedPathFanOutAcrossPeers(t *testing.T) {
126		psk := testKey(t, 0x41)
127		clk := newFakeClock()
128		m, _, _ := newProbingMultipath(t, loopbackPaths(1), psk, clk) // one shared path, "a"
129		if _, _, err := m.Open(0); err != nil {
130			t.Fatalf("Open: %v", err)
131		}
132		t.Cleanup(func() { _ = m.Close() })
133	
134		primary := m.peerState
135		second := bindSecondPeer(t, m, "peer-2", psk, clk)
136	
137		// Preconditions: two bound peers, each with exactly the one boot path "a" over the one
138		// shared socket. Capture each peer's original path object to prove the remove leaves it
139		// untouched.
140		if len(m.peers) != 2 {
141			t.Fatalf("bound peers = %d, want 2", len(m.peers))
142		}
143		if len(m.shared) != 1 {
144			t.Fatalf("shared sockets = %d, want 1", len(m.shared))
145		}
146		primaryOrigA := peerPathByName(primary, "a")
147		secondOrigA := peerPathByName(second, "a")
148		if primaryOrigA == nil || secondOrigA == nil {
149			t.Fatalf("boot path 'a' missing: primary=%v second=%v", pathNamesOfPeer(primary), pathNamesOfPeer(second))
150		}
151		if primaryOrigA.sharedPathState != secondOrigA.sharedPathState {
152			t.Fatal("the two peers' boot path 'a' must VIEW the same shared socket")
153		}
154	
155		// --- AddPath a SHARED path at runtime: the fan-out must reach BOTH peers. ---
156		if err := m.AddPath(config.Path{Name: "shared-b", SourceAddr: netip.MustParseAddr("127.0.0.1")}); err != nil {
157			t.Fatalf("AddPath: %v", err)
158		}
159		if len(m.shared) != 2 {
160			t.Fatalf("shared sockets after add = %d, want 2", len(m.shared))
161		}
162		sharedB := m.shared[1]
163		if sharedB.name != "shared-b" {
164			t.Fatalf("new shared socket name = %q, want %q", sharedB.name, "shared-b")
165		}
166	
167		for _, tc := range []struct {
168			who string
169			p   *peerState
170		}{{"primary", primary}, {"second", second}} {
171			pp := peerPathByName(tc.p, "shared-b")
172			if pp == nil {
173				t.Fatalf("%s peer has no per-(peer,path) state for 'shared-b' after add (fan-out missed it): %v", tc.who, pathNamesOfPeer(tc.p))
174			}
175			// Per-(peer,path) state was instantiated: its OWN codec + prober, VIEWING the ONE shared
176			// socket (not a duplicate socket per peer).
177			if pp.sharedPathState != sharedB {
178				t.Fatalf("%s peer's 'shared-b' does not view the shared socket (per-peer socket duplicated)", tc.who)
179			}
180			if pp.codec == nil {
181				t.Fatalf("%s peer's 'shared-b' has no per-(peer,path) codec", tc.who)
182			}
183			if pp.prober == nil {
184				t.Fatalf("%s peer's 'shared-b' has no per-(peer,path) prober", tc.who)
185			}
186			if pp.peer != tc.p {
187				t.Fatalf("%s peer's 'shared-b' back-references the wrong peerState", tc.who)
188			}
189		}
190		// The two peers minted DISTINCT probers for the shared path (genuine per-(peer,path) state,
191		// not one shared handle).
192		if peerPathByName(primary, "shared-b").prober == peerPathByName(second, "shared-b").prober {
193			t.Fatal("both peers share ONE prober for 'shared-b' — the fan-out did not mint per-peer state")
194		}
195	
196		// --- RemovePath the shared path: the teardown must reach BOTH peers. ---
197		if err := m.RemovePath("shared-b"); err != nil {
198			t.Fatalf("RemovePath: %v", err)
199		}
200		if len(m.shared) != 1 {
201			t.Fatalf("shared sockets after remove = %d, want 1", len(m.shared))
202		}
203		for _, tc := range []struct {
204			who  string
205			p    *peerState
206			orig *peerPathState
207		}{{"primary", primary, primaryOrigA}, {"second", second, secondOrigA}} {
208			if peerPathByName(tc.p, "shared-b") != nil {
209				t.Fatalf("%s peer still holds per-(peer,path) state for 'shared-b' after remove: %v", tc.who, pathNamesOfPeer(tc.p))
210			}
211			if len(tc.p.paths) != 1 {
212				t.Fatalf("%s peer path count after remove = %d, want 1 (remaining paths untouched)", tc.who, len(tc.p.paths))
213			}
214			remaining := peerPathByName(tc.p, "a")
215			if remaining == nil {
216				t.Fatalf("%s peer lost its remaining path 'a' on the remove: %v", tc.who, pathNamesOfPeer(tc.p))
217			}
218			if remaining != tc.orig {
219				t.Fatalf("%s peer's remaining path 'a' object changed on the remove (remaining paths must be untouched)", tc.who)
220			}
221		}
222	}
