1	package bind
2	
3	import (
4		"bytes"
5		"crypto/rand"
6		"net/netip"
7		"testing"
8	
9		"github.com/7mind/wanbond/internal/config"
10		"github.com/7mind/wanbond/internal/frame"
11		"github.com/7mind/wanbond/internal/telemetry"
12	)
13	
14	// bindLazyPeer binds a SECOND concentrator peer over the shared sockets exactly as
15	// bindSecondPeer does, then clears its heavy receive datapath so the peer starts from the
16	// genuine LAZY baseline T91 pins: a configured concentrator peer carries NO ~2048-frame
17	// resequencer ring and NO FEC decoder buffers until its FIRST authenticated source->peer
18	// binding. bindSecondPeer predates lazy instantiation and eagerly stored a resequencer; we
19	// drop it here so every state transition asserted below is driven by PRODUCTION code
20	// (ensurePeerReceiveInstantiated on bind, teardownPeerLocked on session loss), not by the
21	// fixture. Its LIGHT state — psk-derived codecs, per-(peer,path) views, probers, reflector —
22	// survives, which is exactly what lets a trial-decode still authenticate the dormant peer.
23	func bindLazyPeer(t *testing.T, m *Multipath, name string, psk config.Key, clk telemetry.Clock) *peerState {
24		t.Helper()
25		p := bindSecondPeer(t, m, name, psk, clk)
26		p.resequencer.Store(nil)
27		p.fecRecv.Store(nil)
28		return p
29	}
30	
31	// lazyConcentrator stands up a one-shared-socket Multipath whose primary is keyed by pskA and
32	// whose SECOND peer (pskB) is bound LAZILY (no heavy state yet). It returns the bind, both
33	// peers, and the fake clock so a caller can drive per-path liveness deterministically.
34	func lazyConcentrator(t *testing.T, pskA, pskB config.Key) (m *Multipath, primary, second *peerState, clk *fakeClock) {
35		t.Helper()
36		clk = newFakeClock()
37		m, _, _ = newProbingMultipath(t, loopbackPaths(1), pskA, clk)
38		if _, _, err := m.Open(0); err != nil {
39			t.Fatalf("Open: %v", err)
40		}
41		t.Cleanup(func() { _ = m.Close() })
42		primary = m.peerState
43		second = bindLazyPeer(t, m, "peer-b", pskB, clk)
44		if peerPathByName(second, "a") == nil {
45			t.Fatalf("second peer has no view of shared path 'a': %v", pathNamesOfPeer(second))
46		}
47		return m, primary, second, clk
48	}
49	
50	// synthSource returns a distinct spoofable source address for the i-th flood entry. The demux
51	// map is keyed by netip.Addr, so the ADDRESS (not just the port) must differ to occupy a
52	// distinct map slot.
53	func synthSource(i int) netip.AddrPort {
54		return netip.AddrPortFrom(netip.AddrFrom4([4]byte{10, byte(i >> 16), byte(i >> 8), byte(i)}), 41000)
55	}
56	
57	// authProbe encodes an authenticated PROBE under psk on the given path, from a caller-chosen
58	// ProbeSeq (kept strictly increasing across a flood so the reflector's per-path anti-replay
59	// filter never rejects — though binding happens BEFORE reflection and does not depend on it).
60	func authProbe(t *testing.T, psk config.Key, pathID uint8, seq uint64, clk *fakeClock) []byte {
61		t.Helper()
62		raw, err := frame.Encode(psk, frame.Probe{PathID: pathID, ProbeSeq: seq, TimestampNanos: clk.Now().UnixNano(), IsEcho: false})
63		if err != nil {
64			t.Fatalf("encode probe: %v", err)
65		}
66		return raw
67	}
68	
69	// driveConcentratorPathUp brings a per-(peer,path) prober to StateUp through testProbeUpSucc
70	// authenticated probe/echo exchanges reflected under psk, advancing the fake clock by one
71	// probe interval per exchange — the same pattern the sweep tests use.
72	func driveConcentratorPathUp(t *testing.T, pp *peerPathState, psk config.Key, clk *fakeClock) {
73		t.Helper()
74		reflector := telemetry.NewReflector(psk, rand.Reader)
75		for i := 0; i < testProbeUpSucc; i++ {
76			raw, err := pp.prober.SendProbe()
77			if err != nil {
78				t.Fatalf("SendProbe: %v", err)
79			}
80			echo, err := reflector.Reflect(raw)
81			if err != nil {
82				t.Fatalf("reflect probe: %v", err)
83			}
84			clk.advance(testProbeRTT)
85			if err := pp.prober.HandleEcho(echo); err != nil {
86				t.Fatalf("HandleEcho: %v", err)
87			}
88			clk.advance(testProbeInterval - testProbeRTT)
89		}
90		if pp.prober.State() != telemetry.StateUp {
91			t.Fatalf("path %q not Up after %d successes: %v", pp.name, testProbeUpSucc, pp.prober.State())
92		}
93	}
94	
95	// TestConcentratorLazyInstantiationTeardownRebind is the T91 per-peer-lifecycle acceptance: a
96	// configured concentrator peer's HEAVY receive datapath (the resequencer ring + FEC buffers)
97	// is ABSENT before its first authenticated binding, INSTANTIATED on that binding, TORN DOWN
98	// after session/liveness loss (freeing the ring), and RE-INSTANTIATED + passing traffic on the
99	// next authenticated PROBE.
100	func TestConcentratorLazyInstantiationTeardownRebind(t *testing.T) {
101		pskA := testKey(t, 0x11) // primary
102		pskB := testKey(t, 0x22) // lazy second peer
103		m, primary, second, clk := lazyConcentrator(t, pskA, pskB)
104		secondView := peerPathByName(second, "a")
105		dataCodecB, err := frame.NewCodec(pskB)
106		if err != nil {
107			t.Fatalf("build peer B data codec: %v", err)
108		}
109	
110		// (1) Heavy fields absent before the first authenticated binding.
111		if second.resequencer.Load() != nil {
112			t.Fatal("a configured concentrator peer holds a resequencer ring before any binding (heavy state not lazy)")
113		}
114		if second.fecRecv.Load() != nil {
115			t.Fatal("a configured concentrator peer holds FEC receive buffers before any binding")
116		}
117	
118		// (2) An authenticated PROBE from a fresh source binds it to peer B and INSTANTIATES the
119		// heavy receive datapath.
120		src := synthSource(1)
121		m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 1, clk), src)
122		bound, ok := m.lookupPeerBySource(src.Addr())
123		if !ok || bound != second {
124			t.Fatalf("authenticated PROBE did not bind the source to peer B: bound=%v ok=%v", bound, ok)
125		}
126		rq := second.resequencer.Load()
127		if rq == nil {
128			t.Fatal("peer B's resequencer ring was not instantiated on its first authenticated binding")
129		}
130	
131		// Traffic flows: DATA from the now-bound source lands in peer B's freshly-built ring, and
132		// only B's (never the primary's).
133		m.demuxInbound(m.paths[0], mustEncodeData(t, dataCodecB, 100, secondView.id, "hello-b"), src)
134		if it, ok := second.resequencer.Load().Pop(); !ok || !bytes.Equal(it.Payload, []byte("hello-b")) {
135			t.Fatalf("post-bind DATA did not reach peer B's ring: ok=%v payload=%q", ok, it.Payload)
136		}
137		if it, ok := primary.resequencer.Load().Pop(); ok {
138			t.Fatalf("peer B's DATA leaked into the primary ring (%q)", it.Payload)
139		}
140	
141		// (3) Session/liveness loss: the peer is DOWN (no probe echoes fed), so TearDownPeer frees
142		// its ring + FEC buffers and releases its source binding.
143		if m.peerIsLiveLocked(second) {
144			t.Fatal("peer B is unexpectedly live before any echo was fed")
145		}
146		if !m.TearDownPeer("peer-b") {
147			t.Fatal("TearDownPeer refused to tear down a DEAD peer")
148		}
149		if second.resequencer.Load() != nil {
150			t.Fatal("teardown did not free peer B's resequencer ring")
151		}
152		if second.fecRecv.Load() != nil {
153			t.Fatal("teardown did not free peer B's FEC receive buffers")
154		}
155		if _, ok := m.lookupPeerBySource(src.Addr()); ok {
156			t.Fatal("teardown did not release peer B's source->peer binding")
157		}
158	
159		// DATA from the (now unbound) source is dropped — no ring, no binding, never misrouted.
160		m.demuxInbound(m.paths[0], mustEncodeData(t, dataCodecB, 101, secondView.id, "after-teardown"), src)
161		if primary.resequencer.Load() == nil {
162			t.Fatal("primary ring vanished (teardown must never touch another peer)")
163		}
164		if it, ok := primary.resequencer.Load().Pop(); ok {
165			t.Fatalf("post-teardown DATA for peer B leaked into the primary ring (%q)", it.Payload)
166		}
167	
168		// (4) Re-bind: a fresh authenticated PROBE re-instantiates the ring cleanly, and traffic
169		// flows again.
170		m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 2, clk), src)
171		rebound, ok := m.lookupPeerBySource(src.Addr())
172		if !ok || rebound != second {
173			t.Fatalf("re-bind PROBE did not re-bind the source to peer B: bound=%v ok=%v", rebound, ok)
174		}
175		if second.resequencer.Load() == nil {
176			t.Fatal("peer B's ring was not re-instantiated on re-bind")
177		}
178		if second.resequencer.Load() == rq {
179			t.Fatal("re-bind reused the torn-down resequencer instance instead of a fresh one")
180		}
181		m.demuxInbound(m.paths[0], mustEncodeData(t, dataCodecB, 200, secondView.id, "hello-again"), src)
182		if it, ok := second.resequencer.Load().Pop(); !ok || !bytes.Equal(it.Payload, []byte("hello-again")) {
183			t.Fatalf("re-bound peer B did not pass traffic: ok=%v payload=%q", ok, it.Payload)
184		}
185	}
186	
187	// TestConcentratorDemuxCapBoundsBootstrapFlood is the T91 DoS-bound acceptance: a flood of many
188	// distinct spoofed unbound source addresses cannot grow the demux state past the configured cap
189	// and cannot evict or disturb a live bound peer.
190	func TestConcentratorDemuxCapBoundsBootstrapFlood(t *testing.T) {
191		pskA := testKey(t, 0x11) // primary (the live peer under test)
192		pskB := testKey(t, 0x22) // second peer, the flood's nominal target psk
193	
194		t.Run("a flood of spoofed unbound sources binds nothing and disturbs no live bound peer", func(t *testing.T) {
195			m, primary, _, clk := lazyConcentrator(t, pskA, pskB)
196			dataCodecA, err := frame.NewCodec(pskA)
197			if err != nil {
198				t.Fatalf("build primary data codec: %v", err)
199			}
200	
201			// Establish a LIVE bound peer: bind a source to the primary via an authenticated PROBE,
202			// drive its path Up, and leave a DATA frame buffered in its ring.
203			live := synthSource(0)
204			m.demuxInbound(m.paths[0], authProbe(t, pskA, m.paths[0].id, 1, clk), live)
205			if bound, ok := m.lookupPeerBySource(live.Addr()); !ok || bound != primary {
206				t.Fatalf("live source did not bind to the primary: bound=%v ok=%v", bound, ok)
207			}
208			driveConcentratorPathUp(t, m.paths[0], pskA, clk)
209			m.demuxInbound(m.paths[0], mustEncodeData(t, dataCodecA, 500, m.paths[0].id, "live-payload"), live)
210	
211			before := m.peerBySourceLenForTest()
212	
213			// Flood: 500 distinct spoofed sources sending random garbage that verifies under NO psk.
214			const flood = 500
215			for i := 1; i <= flood; i++ {
216				garbage := make([]byte, 96)
217				if _, err := rand.Read(garbage); err != nil {
218					t.Fatalf("draw garbage: %v", err)
219				}
220				m.demuxInbound(m.paths[0], garbage, synthSource(i))
221			}
222	
223			// The flood grew the demux map by nothing (spoofed garbage never authenticates a PROBE,
224			// so it never binds), never evicted the live binding, and never disturbed its ring or
225			// its liveness.
226			if after := m.peerBySourceLenForTest(); after != before {
227				t.Fatalf("spoofed flood grew the demux map from %d to %d entries", before, after)
228			}
229			if bound, ok := m.lookupPeerBySource(live.Addr()); !ok || bound != primary {
230				t.Fatal("the flood evicted or repointed the live source->peer binding")
231			}
232			if m.paths[0].prober.State() != telemetry.StateUp {
233				t.Fatalf("the flood disturbed the live path's liveness: %v", m.paths[0].prober.State())
234			}
235			if it, ok := primary.resequencer.Load().Pop(); !ok || !bytes.Equal(it.Payload, []byte("live-payload")) {
236				t.Fatalf("the flood disturbed the live peer's buffered frame: ok=%v payload=%q", ok, it.Payload)
237			}
238		})
239	
240		t.Run("authenticated bindings clamp at the cap and never evict an existing binding", func(t *testing.T) {
241			m, primary, second, clk := lazyConcentrator(t, pskA, pskB)
242			const capLimit = 4
243			m.maxDemuxSources = capLimit
244			secondView := peerPathByName(second, "a")
245	
246			// The first bound source belongs to the PRIMARY (a DIFFERENT peer than the flood target),
247			// so the cap test also proves cross-peer non-disturbance.
248			live := synthSource(0)
249			m.demuxInbound(m.paths[0], authProbe(t, pskA, m.paths[0].id, 1, clk), live)
250			if bound, ok := m.lookupPeerBySource(live.Addr()); !ok || bound != primary {
251				t.Fatalf("live source did not bind to the primary: bound=%v ok=%v", bound, ok)
252			}
253	
254			// Now flood authenticated PROBEs under pskB from many distinct sources — each WOULD bind
255			// to peer B. Only up to the cap can be admitted; the rest are dropped-on-exhaustion.
256			for i := 1; i <= 50; i++ {
257				m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, uint64(i+1), clk), synthSource(i))
258			}
259	
260			if got := m.peerBySourceLenForTest(); got != capLimit {
261				t.Fatalf("demux map = %d entries, want it clamped at the cap %d", got, capLimit)
262			}
263			// The pre-existing binding was never evicted to make room for a newer source.
264			if bound, ok := m.lookupPeerBySource(live.Addr()); !ok || bound != primary {
265				t.Fatal("cap exhaustion evicted the pre-existing (primary) binding — drop-on-exhaustion must never evict")
266			}
267			// A brand-new source arriving while at cap is refused (bootstrap degrades, no growth).
268			fresh := synthSource(9999)
269			m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 9999, clk), fresh)
270			if _, ok := m.lookupPeerBySource(fresh.Addr()); ok {
271				t.Fatal("a new source bound while the demux map was at its cap (drop-on-exhaustion violated)")
272			}
273			if got := m.peerBySourceLenForTest(); got != capLimit {
274				t.Fatalf("demux map grew past the cap to %d after a post-exhaustion arrival", got)
275			}
276		})
277	}
278	
279	// TestConcentratorLivePeerNeverTornDown pins the invariant that a LIVE (Up) peer is never torn
280	// down regardless of other peers' churn: TearDownPeer refuses it while its path is Up, and a
281	// dormant peer's bind+teardown churn leaves the live peer's ring and binding untouched.
282	func TestConcentratorLivePeerNeverTornDown(t *testing.T) {
283		pskA := testKey(t, 0x11) // primary
284		pskB := testKey(t, 0x22) // the LIVE peer under test
285		pskC := testKey(t, 0x33) // a dormant peer that churns
286	
287		m, _, second, clk := lazyConcentrator(t, pskA, pskB)
288		secondView := peerPathByName(second, "a")
289		third := bindLazyPeer(t, m, "peer-c", pskC, clk)
290		thirdView := peerPathByName(third, "a")
291		dataCodecB, err := frame.NewCodec(pskB)
292		if err != nil {
293			t.Fatalf("build peer B data codec: %v", err)
294		}
295	
296		// Make peer B live: bind a source, instantiate its ring, drive its path Up, buffer a frame.
297		srcB := synthSource(1)
298		m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 1, clk), srcB)
299		driveConcentratorPathUp(t, secondView, pskB, clk)
300		m.demuxInbound(m.paths[0], mustEncodeData(t, dataCodecB, 700, secondView.id, "live-b"), srcB)
301		ringB := second.resequencer.Load()
302		if ringB == nil {
303			t.Fatal("peer B has no ring after binding")
304		}
305	
306		// TearDownPeer REFUSES the live peer.
307		if m.TearDownPeer("peer-b") {
308			t.Fatal("TearDownPeer tore down a LIVE (Up) peer")
309		}
310		if second.resequencer.Load() != ringB {
311			t.Fatal("a refused teardown still swapped/freed the live peer's ring")
312		}
313	
314		// Churn a DORMANT peer: bind peer C (Down), then tear it down. Peer B (live) must be
315		// wholly untouched by that churn.
316		srcC := synthSource(2)
317		m.demuxInbound(m.paths[0], authProbe(t, pskC, thirdView.id, 1, clk), srcC)
318		if third.resequencer.Load() == nil {
319			t.Fatal("dormant peer C did not instantiate on binding")
320		}
321		if !m.TearDownPeer("peer-c") {
322			t.Fatal("TearDownPeer refused to tear down the dead peer C")
323		}
324		if third.resequencer.Load() != nil {
325			t.Fatal("peer C teardown did not free its ring")
326		}
327	
328		// Peer B survived the churn: still Up, still bound, ring intact with its buffered frame.
329		if secondView.prober.State() != telemetry.StateUp {
330			t.Fatalf("peer B lost liveness across peer C's churn: %v", secondView.prober.State())
331		}
332		if bound, ok := m.lookupPeerBySource(srcB.Addr()); !ok || bound != second {
333			t.Fatal("peer B's binding was disturbed by peer C's churn")
334		}
335		if second.resequencer.Load() != ringB {
336			t.Fatal("peer B's ring was swapped by peer C's churn")
337		}
338		if it, ok := second.resequencer.Load().Pop(); !ok || !bytes.Equal(it.Payload, []byte("live-b")) {
339			t.Fatalf("peer B's buffered frame was disturbed by peer C's churn: ok=%v payload=%q", ok, it.Payload)
340		}
341	}
342	
343	// peerBySourceLenForTest reports the number of live source->peer demux bindings (0 when the
344	// map has never been published).
345	func (m *Multipath) peerBySourceLenForTest() int {
346		mp := m.peerBySource.Load()
347		if mp == nil {
348			return 0
349		}
350		return len(*mp)
351	}
352	
353	// mustEncodeData encodes a DATA frame or fails the test.
354	func mustEncodeData(t *testing.T, codec *frame.Codec, seq uint64, pathID uint8, payload string) []byte {
355		t.Helper()
356		raw, err := codec.Encode(nil, frame.Data{OuterSeq: seq, PathID: pathID, Payload: []byte(payload)})
357		if err != nil {
358			t.Fatalf("encode DATA: %v", err)
359		}
360		return raw
361	}
